# Bad - Strategy with behavior as dataclass
@dataclass(frozen=True)
class RebalanceStrategy(Strategy):
    target_allocations: dict[str, float]

    def generate_actions(self, date: date, portfolio: Portfolio) -> Iterator[Action]:
        # Complex rebalancing logic here...
        pass  # This is behavior, not data!

# Bad - Service with methods as dataclass
@dataclass
class TransactionProcessor:
    config: Config

    def process(self, txn: Transaction) -> Result:
        # Complex processing logic...
        pass

# Good - Strategy with behavior as regular class
class RebalanceStrategy(Strategy):
    def __init__(self, target_allocations: dict[str, float]) -> None:
        """Initialize rebalancing strategy."""
        if not (0.999 <= sum(target_allocations.values()) <= 1.001):
            raise ValueError("Allocations must sum to 1.0")
        self._target_allocations = target_allocations

    def generate_actions(self, date: date, portfolio: Portfolio) -> Iterator[Action]:
        # Complex rebalancing logic here...
        pass

# Good - Action parameter container as dataclass
@dataclass(frozen=True)
class BuyAction(Action):
    """Encapsulates buy parameters - minimal behavior."""
    asset_id: str
    date: date
    units: float | None
    value: float | None

    def execute(self, portfolio: Portfolio) -> ActionResult:
        # Minimal behavior: just delegates to portfolio
        return portfolio.buy(...)

notes.note:
```python
# Bad - Factory method makes this behavior, not just data
@dataclass(frozen=True)
class QueryResult:
    _data: pd.DataFrame

    @classmethod
    def from_query(cls, sql: str, conn: Connection) -> QueryResult:
        # Factory method = behavior!
        ...

# Good - Regular class when factory methods are needed
class QueryResult:
    """Result of a database query."""
    __slots__ = ("_data",)

    def __init__(self, data: pd.DataFrame) -> None:
        self._data = data

    @classmethod
    def from_query(cls, sql: str, conn: Connection) -> QueryResult:
        data = pd.read_sql(sql, conn)
        return cls(data)
```

```python
# Bad - Collection that sorts/transforms input as dataclass
@dataclass(frozen=True)
class EventSchedule:
    events: tuple[Event, ...]
    _by_date: dict[date, list[Event]] = field(init=False)  # Awkward!

    def __post_init__(self) -> None:
        # Complex initialization doesn't belong in __post_init__
        self._by_date = self._build_index()

# Good - Regular class for collections with initialization logic
class EventSchedule:
    """Collection of events stored in sorted order."""
    __slots__ = ("_events",)

    def __init__(self, events: Iterable[Event]) -> None:
        self._events: tuple[Event, ...] = tuple(sorted(events))

    @property
    def events(self) -> Sequence[Event]:
        return self._events
```
